  1→import './profilepostcards.css';
  2→import { useAuth } from '../../../../Context/useAuth';
  3→import { useInfiniteQuery, useQueryClient } from '@tanstack/react-query';
  4→import { deleteJournal, deleteJournalImage, getUserJournals } from '../../../../../API/Api';
  5→import { useEffect, useCallback } from 'react';
  6→import { FadeLoader, MoonLoader } from 'react-spinners';
  7→import ParseContent from '../parseData';
  8→import { useInView } from 'react-intersection-observer';
  9→import { useState } from 'react';
 10→import { AnimatePresence, motion } from 'framer-motion';
 11→import { handleCLickContent } from '../../../../../helpers/handleClicks';
 12→import { useNavigate } from 'react-router-dom';
 13→import EditJournal from './editJournal';
 14→import { useAddViewsMutation, useUpdateJournalPrivacyMutation } from '../../../../utils/useMutation';
 15→import VerifiedBadge from '../../../Badge/VerifiedBadge';
 16→import { handleImageFallback } from '../../../../utils/handleImageFallback';
 17→import { getCanvasPreview } from '../../../../utils/canvasDoc';
 18→import CanvasPreview from '../CanvasPreview/CanvasPreview';
 19→
 20→const ProfilePostCards = () =>{
 21→    const queryClient = useQueryClient();
 22→    const {user, session}= useAuth();
 23→    const navigate = useNavigate();
 24→
 25→    const [showEditor, setShowEditor] = useState(null);
 26→
 27→    const {ref, inView} = useInView({
 28→        threshold: 0.2
 29→    })
 30→
 31→    const settingsList = [
 32→        {
 33→            label: 'Delete journal',
 34→            className: 'delete-button',
 35→            actionDelete: (e, journalId) => handleClickDeleteJournal(e, journalId),
 36→            icon:
 37→            <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill="none">
 38→                <path d="M10 12V17" stroke="rgb(255, 48, 48)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 39→                <path d="M14 12V17" stroke="rgb(255, 48, 48)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 40→                <path d="M4 7H20" stroke="rgb(255, 48, 48)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 41→                <path d="M6 10V18C6 19.6569 7.34315 21 9 21H15C16.6569 21 18 19.6569 18 18V10" stroke="rgb(255, 48, 48)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 42→                <path d="M9 5C9 3.89543 9.89543 3 11 3H13C14.1046 3 15 3.89543 15 5V7H9V5Z" stroke="rgb(255, 48, 48)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 43→            </svg>
 44→        },
 45→        {
 46→            label: 'Edit journal',
 47→            className: 'edit-button',
 48→            actionEdit: (e, journalContent, journalId, journalTitle) => handleClickEdit(e, journalContent, journalId, journalTitle), // still in progress
 49→            icon: 
 50→            <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill="none">
 51→                <path d="M18.3785 8.44975L11.4637 15.3647C11.1845 15.6439 10.8289 15.8342 10.4417 15.9117L7.49994 16.5L8.08829 13.5582C8.16572 13.1711 8.35603 12.8155 8.63522 12.5363L15.5501 5.62132M18.3785 8.44975L19.7927 7.03553C20.1832 6.64501 20.1832 6.01184 19.7927 5.62132L18.3785 4.20711C17.988 3.81658 17.3548 3.81658 16.9643 4.20711L15.5501 5.62132M18.3785 8.44975L15.5501 5.62132" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 52→                <path d="M5 20H19" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 53→            </svg>
 54→        },
 55→        {
 56→            label: 'Only me',
 57→            className: 'only-me-bttn',
 58→            actionOnlyMe: (e, privacy, journalId) => {handleEditJournalPrivacy(e, privacy, journalId)},
 59→            icon: 
 60→            <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 16 16" fill="none">
 61→                <g fill="#000000">
 62→                    <path fillRule="evenodd" d="M5.58 7C5.835 5.124 6.667 3.335 8 1.836a10.074 10.074 0 011.806 2.878.75.75 0 101.388-.568 11.412 11.412 0 00-1.322-2.372A6.503 6.503 0 0114.5 8 .75.75 0 0016 8a8 8 0 10-11.31 7.285.75.75 0 10.622-1.365A6.504 6.504 0 011.519 8.5h2.503c.04.563.122 1.12.248 1.668a.75.75 0 101.462-.336c-.1-.438-.17-.883-.205-1.332H7A.75.75 0 007 7H5.58zM4.07 7H1.576a6.508 6.508 0 014.552-5.226A11.095 11.095 0 004.068 7z" clipRule="evenodd"/>
 63→                    <path d="M11.75 12.25a.75.75 0 00-1.5 0v.5a.75.75 0 001.5 0v-.5z"/>
 64→                    <path fillRule="evenodd" d="M8.518 9.012c.035-.627.13-1.235.366-1.738.174-.37.435-.704.816-.94C10.08 6.101 10.52 6 11 6c.48 0 .921.1 1.3.334.381.236.642.57.816.94.236.503.331 1.111.366 1.738A2.25 2.25 0 0115.5 11.25v2.5A2.25 2.25 0 0113.25 16h-4.5a2.25 2.25 0 01-2.25-2.25v-2.5a2.25 2.25 0 012.018-2.238zM10.022 9c.032-.481.102-.838.22-1.087a.662.662 0 01.245-.302c.09-.055.243-.111.513-.111s.423.056.513.111c.087.054.17.141.246.302.117.249.187.606.219 1.087h-1.956zm3.228 1.5a.75.75 0 01.75.75v2.5a.75.75 0 01-.75.75h-4.5a.75.75 0 01-.75-.75v-2.5a.75.75 0 01.75-.75h4.5z" clipRule="evenodd"/>
 65→                </g>
 66→            </svg>
 67→        },
 68→        {
 69→            label: 'public',
 70→            className: 'public-post-bttn',
 71→            actionPublic: (e, privacy, journalId) => {handleEditJournalPrivacy(e, privacy, journalId)},
 72→            icon:
 73→            <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 16 16" fill="none"><path fill="#000000" fillRule="evenodd" d="M8 0a8 8 0 100 16A8 8 0 008 0zM6.128 1.774A6.508 6.508 0 001.576 7H4.07a11.095 11.095 0 012.06-5.226zm3.744 0A11.096 11.096 0 0111.932 7h2.492a6.508 6.508 0 00-4.552-5.226zM10.42 7C10.165 5.124 9.333 3.335 8 1.836 6.667 3.335 5.835 5.124 5.58 7h4.84zM5.527 8.5h4.946C10.31 10.557 9.451 12.533 8 14.164 6.55 12.533 5.691 10.557 5.527 8.5zm-1.505 0H1.52a6.505 6.505 0 004.61 5.726C4.896 12.525 4.163 10.555 4.021 8.5zm5.85 5.726c1.231-1.701 1.964-3.671 2.106-5.726h2.503a6.505 6.505 0 01-4.61 5.726z" clipRule="evenodd"/></svg>
 74→        }
 75→    ]
 76→
 77→    const [showSettings, setShowSettings] = useState(null);
 78→    const [showConfirmationBttn, setShowConfirmationBttn] = useState(null);
 79→    const [journalData, setJournalData] = useState(null);
 80→    const [isDeletingJournal, setIsDeletingJournal] = useState(false);
 81→    const [journalIsDeleted, setJournalIsDeleted] = useState(false);
 82→    const [viewMode, setViewMode] = useState('grid');
 83→    
 84→    const {
 85→        data,
 86→        fetchNextPage,
 87→        hasNextPage,
 88→        isFetchingNextPage,
 89→        isLoading,
 90→    } = useInfiniteQuery({
 91→        queryKey: ['userJournals', user?.userData?.[0].id],
 92→        queryFn: ({queryKey, pageParam}) => getUserJournals(pageParam, 5, queryKey[1], session?.access_token),
 93→        getNextPageParam: (lastPage) =>{
 94→            if(lastPage.hasMore){
 95→                const lastJournal = lastPage?.data[lastPage?.data.length - 1];
 96→                return new Date(lastJournal.created_at).toISOString();
 97→            } else {
 98→                return undefined;
 99→            }
100→        },
101→        enabled: !!user?.userData?.[0].id,
102→        refetchOnWindowFocus: false,
103→    })
104→
105→    
106→    const clickContent = handleCLickContent(navigate);
107→    const mutateViews = useAddViewsMutation(session);
108→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType = null, canvasDoc = null) => {
109→        const formadata = new FormData();
110→
111→        formadata.append('journalId', journalId);
112→        mutateViews.mutate(formadata);
113→        clickContent(e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType, canvasDoc)
114→    }
115→
116→    const mutatePrivacy = useUpdateJournalPrivacyMutation(session);
117→    const handleEditJournalPrivacy = (e, privacy, journalId) =>{
118→        e.stopPropagation();
119→        const onlyme = privacy === 'public' ? 'private' : 'public'
120→        const formdata = new FormData();
121→
122→        formdata.append('journalId', journalId);
123→        formdata.append('privacy', onlyme);
124→        mutatePrivacy.mutate(formdata);    
125→    }
126→
127→    const handleClickSettings = (e, journalId) =>{
128→        e.stopPropagation();
129→        setShowSettings(showSettings === journalId ? null : journalId)
130→    }
131→
132→    const handleClickDeleteJournal = (e, journalId) =>{
133→        e.stopPropagation();
134→        setShowConfirmationBttn(showConfirmationBttn === journalId ? null : journalId)
135→        setShowSettings(null)
136→    }
137→
138→    const handleConfirmDeleteJournal = async(e, journalId, token, image_url) =>{
139→        e.stopPropagation();
140→
141→        const imageUrlArray = [image_url];
142→        const queryKey = ['userJournals', user?.userData?.[0].id];
143→        let previousUserJournals = null;
144→        // console.log({
145→        //     journalId: journalId,
146→        //     image_url: imageUrlArray,
147→        //     token: token
148→        // })
149→
150→        try {
151→            setIsDeletingJournal(true);
152→            previousUserJournals = queryClient.getQueryData(queryKey);
153→
154→            queryClient.setQueryData(queryKey, (old) => {
155→                if (!old || !Array.isArray(old.pages)) return old;
156→
157→                return {
158→                    ...old,
159→                    pages: old.pages.map((page) => ({
160→                        ...page,
161→                        data: Array.isArray(page?.data)
162→                            ? page.data.filter((journal) => journal?.id !== journalId)
163→                            : page?.data
164→                    }))
165→                };
166→            });
167→
168→            const deleteJournalPromise = deleteJournal(journalId, token,)
169→            const deleteImageJournalPromise = image_url ? deleteJournalImage(token, imageUrlArray) : Promise.resolve(null);
170→
171→            const [deletePostJournal, deletePostJournalImage] = await Promise.allSettled([
172→                deleteJournalPromise,
173→                deleteImageJournalPromise,
174→            ])
175→            if(deletePostJournal || deletePostJournalImage){
176→                console.log({deletePostJournal: deletePostJournal, deletePostJournalImage: deletePostJournalImage})
177→            }
178→
179→            if(deletePostJournal.status !== 'fulfilled'){
180→                queryClient.setQueryData(queryKey, previousUserJournals);
181→                throw deletePostJournal.reason || new Error('failed to delete journal');
182→            }
183→
184→            setJournalIsDeleted(true)
185→            queryClient.invalidateQueries({ queryKey: queryKey });
186→            queryClient.invalidateQueries({ queryKey: ['journals'] });
187→            queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'] });
188→
189→            setTimeout(() =>{
190→                setIsDeletingJournal(false)
191→                setJournalIsDeleted(false)
192→                setShowConfirmationBttn(null)
193→            }, 1500)
194→
195→        } catch (error) {
196→            if(previousUserJournals){
197→                queryClient.setQueryData(queryKey, previousUserJournals);
198→            }
199→            console.error("Error deleting journal:", error);
200→            setIsDeletingJournal(false);
201→        }
202→    }
203→
204→    const handleClickEdit = (e, journalContent, journalId, journalTitle) =>{
205→        e.stopPropagation();
206→        setShowSettings(null)
207→        const data = {
208→            content: journalContent,
209→            id: journalId,
210→            title: journalTitle
211→        }
212→        setJournalData(data);
213→        setShowEditor(showEditor === journalId ? null : journalId);
214→    }
215→
216→    const handleClickCloseEditor = () => {
217→        setShowEditor(null)
218→    }
219→
220→    useEffect(() =>{
221→        console.log(data)
222→    }, [data])
223→
224→    useEffect(() =>{
225→        const handleClickOutsideSettings = (e) => {
226→            e.stopPropagation();
227→            if(showSettings !== null && !e.target.closest('.user-post-settings')){
228→                setShowSettings(null)
229→            }
230→        }
231→        
232→        document.addEventListener('click', handleClickOutsideSettings);
233→
234→        return () => {
235→            document.removeEventListener('click', handleClickOutsideSettings)
236→        }
237→    }, [showSettings])
238→
239→
240→    const isLoadingMore = isFetchingNextPage || !hasNextPage
241→    useEffect(() =>{
242→        if(inView && !isLoadingMore){
243→            fetchNextPage();
244→        }
245→    }, [fetchNextPage, isLoadingMore, inView])
246→
247→    const handleToggleView = useCallback(() => {
248→        setViewMode((prev) => (prev === 'list' ? 'grid' : 'list'));
249→    }, []);
250→
251→
252→    const journals = data?.pages.flatMap((page) => page.data) || [];
253→    if(isLoading){
254→        return(
255→            <>
256→            <div className='profile-postcards-loading-container'>
257→                <MoonLoader loading={isLoading} color="var(--loader-color)" size={20} speedMultiplier={0.5}/>
258→            </div>
259→            </>
260→        )
261→    }
262→    if(data && journals?.length === 0){
263→        return(
264→            <div className='profile-postcards-loading-container'>
265→                No post available!
266→            </div>
267→        )
268→    }
269→    return(
270→        <>
271→        <div className='profile-postcards-parent-container'>
272→            <div className="postcards-header-row">
273→                <h2 className="postcards-heading">
274→                    Posts <span className="postcards-count">({journals.length})</span>
275→                </h2>
276→                <div className="postcards-header-actions">
277→                    <button
278→                        className={`postcards-view-toggle-btn ${viewMode === 'grid' ? 'is-active' : ''}`}
279→                        onClick={handleToggleView}
280→                        title={viewMode === 'grid' ? 'Switch to list' : 'Switch to grid'}
281→                    >
282→                        {viewMode === 'grid' ? (
283→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-520v-320h320v320H120Zm0 400v-320h320v320H120Zm400-400v-320h320v320H520Zm0 400v-320h320v320H520Z"/></svg>
284→                        ) : (
285→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-200v-560h720v560H120Z"/></svg>
286→                        )}
287→                    </button>
288→                </div>
289→            </div>
290→
291→            {viewMode === 'grid' ? (
292→                <div className="postcards-grid-view">
293→                    {journals.map((journal) => {
294→                        const isCanvasPost = journal?.post_type === 'canvas';
295→                        const parsedContent = ParseContent(journal?.content);
296→                        const canvasPreview = isCanvasPost ? getCanvasPreview(journal?.canvas_doc) : null;
297→                        const wholeText = isCanvasPost ? canvasPreview?.wholeText || '' : parsedContent?.wholeText || '';
298→                        const previewText = isCanvasPost ? canvasPreview?.slicedText || '' : parsedContent?.slicedText || '';
299→                        const thumbnail = isCanvasPost ? null : parsedContent?.firstImage?.src;
300→                        return (
301→                            <motion.div
302→                                key={journal.id}
303→                                className={`postcards-grid-item${isCanvasPost ? ' is-canvas-card' : ''}`}
304→                                initial={{ opacity: 0, scale: 0.95 }}
305→                                animate={{ opacity: 1, scale: 1 }}
306→                                transition={{ duration: 0.25, ease: 'easeOut' }}
307→                                onClick={(e) => viewContent(e, journal.content, wholeText, journal.title, journal.users.id, journal.users.name, journal.users.image_url, journal.created_at, journal.id, journal.has_liked, journal.comment_count?.[0].count, journal.has_bookmarked, journal.like_count?.[0].count, journal.bookmark_count?.[0].count, journal.users.badge, journal?.post_type, journal?.canvas_doc)}
308→                            >
309→                                {showEditor === journal.id && (
310→                                    <EditJournal journalData={journalData ? journalData : {}} onClose={handleClickCloseEditor}/>
311→                                )}
312→
313→                                {showConfirmationBttn === journal.id && (
314→                                    <AnimatePresence>
315→                                    <div className="confirmation-delete-bg">
316→                                        {journalIsDeleted && (
317→                                            <motion.div
318→                                                className='journal-is-deleted-message-container'
319→                                                initial={{opacity: 0, scale: 0}}
320→                                                animate={{opacity: 1, scale: 1, transition:{type: 'tween', duration: 0.1}}}
321→                                                exit={{y: -900, opacity: 0, transition:{type:'tween', duration: 0.5, ease: 'easeOut'}}}
322→                                            >
323→                                                Journal deleted successfuly!
324→                                                <svg xmlns="http://www.w3.org/2000/svg" height="44px" viewBox="0 -960 960 960" width="44px" fill="#00d61dff"><path d="M268-240 42-466l57-56 170 170 56 56-57 56Zm226 0L268-466l56-57 170 170 368-368 56 57-424 424Zm0-226-57-56 198-198 57 56-198 198Z"/></svg>
325→                                            </motion.div>
326→                                        )}
327→
328→                                        {isDeletingJournal && (
329→                                            <div className='delete-journal-loader-container'>
330→                                                <FadeLoader loading={isDeletingJournal} speedMultiplier={2}/>
331→                                                <p style={{margin: '0', padding: '0', fontWeight: 760}}>Deleting the journal...</p>
332→                                            </div>
333→                                        )}
334→
335→                                        <motion.div
336→                                            className="confirmation-delete-container"
337→                                            initial={{opacity:0 ,scale:0}}
338→                                            animate={{opacity:1, scale:1, transition: {type: "tween", duration: 0.1}}}
339→                                            exit={{opacity:0, scale:0, transition: {type: "tween", duration: 0.1}}}
340→                                        >
341→                                            <div className="confirmation-delete-heading">
342→                                                Do you want to delete the journal?
343→                                            </div>
344→                                            <div className="confirm-buttons-container">
345→                                                <div onClick={(e) => handleConfirmDeleteJournal(e, journal.id, session?.access_token, parsedContent?.firstImage?.src)} className="confirm-buttons-yes">Yes</div>
346→                                                <div onClick={() => setShowConfirmationBttn(null)} className="confirm-buttons-cancel">Cancel</div>
347→                                            </div>
348→                                        </motion.div>
349→                                    </div>
350→                                    </AnimatePresence>
351→                                )}
352→
353→                                {isCanvasPost ? (
354→                                    <div className="postcards-grid-img-wrap">
355→                                        <CanvasPreview canvasDoc={journal?.canvas_doc} />
356→                                    </div>
357→                                ) : thumbnail ? (
358→                                    <div className="postcards-grid-img-wrap">
359→                                        <img className="postcards-grid-thumb" src={thumbnail} alt={journal?.title ? `${journal.title} cover image` : "Post cover image"} loading="lazy" onError={handleImageFallback} />
360→                                    </div>
361→                                ) : null}
362→                                <div className="postcards-grid-body">
363→                                    <h3 className="postcards-grid-title">{journal.title.length > 32 ? `${journal.title.substring(0, 32)}...` : journal.title}</h3>
364→                                    {previewText && (
365→                                        <p className="postcards-grid-snippet">{previewText.length > 50 ? `${previewText.substring(0, 50)}...` : previewText}</p>
366→                                    )}
367→                                    <div className="postcards-grid-body-footer">
368→                                        <div className="user-post-privacy">
369→                                            {journal.privacy === 'public' && (
370→                                                <svg xmlns="http://www.w3.org/2000/svg" width="14px" height="14px" viewBox="0 0 16 16" fill="none"><path fill="currentColor" fillRule="evenodd" d="M8 0a8 8 0 100 16A8 8 0 008 0zM6.128 1.774A6.508 6.508 0 001.576 7H4.07a11.095 11.095 0 012.06-5.226zm3.744 0A11.096 11.096 0 0111.932 7h2.492a6.508 6.508 0 00-4.552-5.226zM10.42 7C10.165 5.124 9.333 3.335 8 1.836 6.667 3.335 5.835 5.124 5.58 7h4.84zM5.527 8.5h4.946C10.31 10.557 9.451 12.533 8 14.164 6.55 12.533 5.691 10.557 5.527 8.5zm-1.505 0H1.52a6.505 6.505 0 004.61 5.726C4.896 12.525 4.163 10.555 4.021 8.5zm5.85 5.726c1.231-1.701 1.964-3.671 2.106-5.726h2.503a6.505 6.505 0 01-4.61 5.726z" clipRule="evenodd"/></svg>
371→                                            )}
372→                                            {journal.privacy === 'private' && (
373→                                                <svg xmlns="http://www.w3.org/2000/svg" width="14px" height="14px" viewBox="0 0 24 24" fill="none">
374→                                                    <path d="M7 10.0288C7.47142 10 8.05259 10 8.8 10H15.2C15.9474 10 16.5286 10 17 10.0288M7 10.0288C6.41168 10.0647 5.99429 10.1455 5.63803 10.327C5.07354 10.6146 4.6146 11.0735 4.32698 11.638C4 12.2798 4 13.1198 4 14.8V16.2C4 17.8802 4 18.7202 4.32698 19.362C4.6146 19.9265 5.07354 20.3854 5.63803 20.673C6.27976 21 7.11984 21 8.8 21H15.2C16.8802 21 17.7202 21 18.362 20.673C18.9265 20.3854 19.3854 19.9265 19.673 19.362C20 18.7202 20 17.8802 20 16.2V14.8C20 13.1198 20 12.2798 19.673 11.638C19.3854 11.0735 18.9265 10.6146 18.362 10.327C18.0057 10.1455 17.5883 10.0647 17 10.0288M7 10.0288V8C7 5.23858 9.23858 3 12 3C14.7614 3 17 5.23858 17 8V10.0288" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
375→                                                </svg>
376→                                            )}
377→                                        </div>
378→                                        <div className="user-post-settings">
379→                                            <svg onClick={(e) => handleClickSettings(e, journal.id)} xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z"/></svg>
380→                                        </div>
381→                                    </div>
382→                                </div>
383→
384→                                {showSettings === journal.id && (
385→                                    <AnimatePresence>
386→                                        <motion.div
387→                                            initial={{opacity:0, scale:0, x: "-50%", y: "-50%"}}
