 21→const ToolBarForEdit = () =>{
 22→    //bold and italic style are textFormatTypeStrings
 23→    const [editor] = useLexicalComposerContext();
 24→
 25→    const applyTextFormat = (format) => {
 26→        editor.dispatchCommand(FORMAT_TEXT_COMMAND, format)
 27→    }
 28→
 29→    //heading node (H1, H2, H3)
 30→    const setHeading = (tag) => {
 31→        editor.update(() => {
 32→            const selection = $getSelection();
 33→            if ($isRangeSelection(selection)) {
 34→                const anchorNode = selection.anchor.getNode();
 35→                
 36→                let element;
 37→                try {
 38→                    element = anchorNode.getKey() === 'root' //checking if anchorNode itselt is the root
 39→                        ? anchorNode  //if not then use getTopLevelElement() method first then as a fallback use getTopLevelElementOrThrow() method
 40→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
 41→                } catch (e) {
 42→                    console.error('Could not get top level element:', e);
 43→                    return;
 44→                }
 45→
 46→                if (!element) return;
 47→
 48→                const type = typeof element.getType === 'function' ? element.getType() : null; //check if elements have getType() === function sometimes nodes dont have getType
 49→                // console.log('Element type:', type);
 50→
 51→                if (type && type !== "paragraph" && type !== "heading") { //only proceed if element is paragraph or heading
 52→                    return;
 53→                }
 54→
 55→                const isActive = $isHeadingNode(element) && element.getTag() === tag; //checking if element.getTag() === 'tag. returns a boolean
 56→
 57→                //use $setBlocksType to change the block type
 58→                //return paragraph if already active(toggle back) otherwise create heading
 59→                $setBlocksType(selection, () => 
 60→                    isActive ? $createParagraphNode() : $createHeadingNode(tag)
 61→                );
 62→            }
 63→        })
 64→    }
 65→
 66→    //align element (left, center, right) using FORMAT_ELEMENT_COMMAND values 'left'|'center'|'right
 67→    const setAlignment = (value) => {
 68→        editor.dispatchCommand(FORMAT_ELEMENT_COMMAND, value);
 69→    }
 70→
 71→    //quote block (toggle)
 72→    const setQuote = () => {
 73→        editor.update(() => {
 74→            const selection = $getSelection();
 75→            if ($isRangeSelection(selection)) {
 76→                const anchorNode = selection.anchor.getNode();
 77→
 78→                let element;
 79→                try {
 80→                    element = anchorNode.getKey() === 'root'
 81→                        ? anchorNode
 82→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
 83→                } catch (e) {
 84→                    console.error('Could not get top level element:', e);
 85→                    return;
 86→                }
 87→
 88→                if (!element) return;
 89→
 90→                const type = typeof element.getType === 'function' ? element.getType() : null;
 91→                if (type && type !== "paragraph" && type !== "heading" && type !== "quote") {
 92→                    return;
 93→                }
 94→
 95→                const isActive = $isQuoteNode(element);
 96→
 97→                $setBlocksType(selection, () =>
 98→                    isActive ? $createParagraphNode() : $createQuoteNode()
 99→                );
100→            }
101→        })
102→    }
