 21→class ErrorBoundary extends React.Component {
 22→  state = { error: null };
 23→  static getDerivedStateFromError(error) {
 24→    return { error };
 25→  }
 26→  render() {
 27→    if (this.state.error) {
 28→      return <div>Error: {this.state.error.message}</div>;
 29→    }
 30→    return this.props.children;
 31→  }
 32→}
 33→
 34→/* theme for mapping css classes to lexical rols */
 35→const theme = {
 36→    paragraph: 'editor-paragraph',
 37→    heading: 'editor-heading',
 38→}
 39→
 40→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, onSwitchToCanvas}) => {
 41→    const [editor] = useLexicalComposerContext();
 42→    const [editorState, setEditorState] = useState(null);
 43→    const [hasContent, setHasContent] = useState(false);
 44→    const [isSending, setIsSending] = useState(false);
 45→
 46→    const {session, user} = useAuth();
 47→
 48→    const queryClient = useQueryClient();
 49→
 50→    const handleClickSave = async(e, title) =>{
 51→        e.stopPropagation();
 52→        setIsSending(true)
 53→        try {
 54→            const formdata = new FormData();
 55→            if(title && editorState){
 56→                formdata.append('title', title)
 57→                formdata.append('content', editorState)
 58→            }
 59→            const saveData = await saveJournal(session?.access_token, formdata)
 60→
 61→            if(saveData){
 62→                console.log(saveData)
 63→                queryClient.invalidateQueries({queryKey: ['journals']});
 64→                queryClient.invalidateQueries({queryKey: ['userJournals', user?.userData?.[0].id]})
 65→            }
 66→
 67→            setIsSending(false)
 68→        } catch (error) {
 69→            console.error("Error saving journal:", error);
 70→        }finally {
 71→            setIsSending(false)
 72→            setHasContent(false)
 73→            onCloseOnSave();
 74→            addUploadImagesPath([])
 75→        }
 76→
 77→    }
 78→
 79→    const onchange = useCallback((state) => {
 80→        const jsonb = JSON.stringify(state.toJSON());
 81→        setEditorState(jsonb)
 82→
 83→        state.read(() => {
 84→            const root = $getRoot();
 85→
 86→            const children = root.getChildren();
 87→
 88→            const hasEnoughParagraphNodes = children.length > 1
 89→            const hasParargraphSize = children[0]?.__size > 0
 90→
 91→            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
 92→            setHasContent(hasContent);
 93→
 94→            // Calculate word count
 95→            const text = root.getTextContent().trim();
 96→            const words = text ? text.split(/\s+/).length : 0;
 97→            setWordCount(words);
 98→        })
 99→    }, [setWordCount])
100→
101→    return(
102→        <>
103→        {/* Toolbar above content */}
104→        <div className="toolbar-wrapper">
105→            <ToolBar addUploadedImagePath={addUploadImagesPath} onSwitchToCanvas={onSwitchToCanvas}/>
106→        </div>
107→
108→        {/* Bar loader directly under toolbar */}
109→        <div className="editor-loader-wrapper">
110→            {isSending && (
111→                <BarLoader loading={isSending} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
112→            )}
113→        </div>
114→
115→        {/* Editor content area */}
116→        <div className="editor-shell">
117→            <RichTextPlugin
118→            contentEditable={
119→            <ContentEditable
120→            className="editor-input"
121→            aria-placeholder="Write your thoughts here..."
122→            placeholder={<div className="editor-placeholder">Write your thoughts here...</div>}/>
123→            }
124→            ErrorBoundary={LexicalErrorBoundary}
125→            />
126→
127→            <ImagePlugin addUploadedImagePath={addUploadImagesPath}/>
128→            <HistoryPlugin/>
129→            <OnChangePlugin onChange={onchange}/>
130→
131→        </div>
132→
133→        {/* Footer: word count + save */}
134→        <div className='editor-footer'>
135→            <span className="editor-word-count">
136→                {wordCount} {wordCount === 1 ? 'word' : 'words'}
137→            </span>
138→            <button disabled={!title || !hasContent || isSending} onClick={(e) =>handleClickSave(e, title)} className={title && hasContent && !isSending ? 'editor-save-bttn' : 'editor-save-bttn-disabled'}>
139→                Share
140→            </button>
141→        </div>
142→        </>
143→    )
144→}
145→
146→export default EditorInner;
