577→    width: 28px;
578→    height: 28px;
579→    border: 3px solid rgba(255, 255, 255, 0.2);
580→    border-top: 3px solid var(--editor-accent);
581→    border-radius: 50%;
582→    animation: image-spin 0.8s linear infinite;
583→}
584→@keyframes image-spin {
585→    0% { transform: rotate(0deg); }
586→    100% { transform: rotate(360deg); }
587→}
588→
589→/* ── Full-screen image view ── */
590→.image-view {
591→    position: fixed;
592→    top: 0;
593→    left: 0;
594→    width: 100vw;
595→    height: 100vh;
596→    object-fit: contain;
597→    background: rgba(0, 0, 0, 0.7);
598→    z-index: 9999;
599→    cursor: zoom-out;
600→    box-sizing: border-box;
601→}
